namespace sv_75ac3023a9864966becc6c03e7b6a72b.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public sealed class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#1b6ec2";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            OnChanged?.Invoke();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            OnChanged?.Invoke();
        }
    }

    /// <summary>
    /// Raised whenever Theme or AccentColor changes.
    /// Subscribers must call StateHasChanged / re-render as needed.
    /// </summary>
    public event Action? OnChanged;
}

export function applyTheme(theme, accentColor) {
    const root = document.documentElement;
    root.setAttribute("data-theme", theme);
    root.style.setProperty("--accent-color", accentColor);
}

@* Interactive component that bridges ThemeService state to the DOM via JS interop. *@
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@inject IJSRuntime JS
@implements IAsyncDisposable

@code {
    private IJSObjectReference? _module;

    protected override void OnInitialized()
    {
        ThemeSvc.OnChanged += HandleThemeChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/theme.js");
            await ApplyThemeAsync();
        }
    }

    private async void HandleThemeChanged()
    {
        await InvokeAsync(async () =>
        {
            await ApplyThemeAsync();
            StateHasChanged();
        });
    }

    private async Task ApplyThemeAsync()
    {
        if (_module is null) return;
        await _module.InvokeVoidAsync("applyTheme",
            ThemeSvc.Theme.ToString().ToLowerInvariant(),
            ThemeSvc.AccentColor);
    }

    public async ValueTask DisposeAsync()
    {
        ThemeSvc.OnChanged -= HandleThemeChanged;
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}

@* Shows current theme in the header. Runs interactive so it can subscribe to ThemeService. *@
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<span class="theme-indicator" title="Current theme">
    @GetIcon() @ThemeSvc.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChanged += HandleChanged;
    }

    private void HandleChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetIcon() => ThemeSvc.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    public void Dispose()
    {
        ThemeSvc.OnChanged -= HandleChanged;
    }
}

@* A quick toggle button any interactive page can drop in. *@
@inject ThemeService ThemeSvc
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="Toggle">
    @GetIcon() @ThemeSvc.Theme
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChanged += HandleChanged;
    }

    private void Toggle()
    {
        ThemeSvc.Theme = ThemeSvc.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
    }

    private string GetIcon() => ThemeSvc.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private void HandleChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeSvc.OnChanged -= HandleChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group d-block" role="group">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            var theme = t;
            <button class="btn @(ThemeSvc.Theme == theme ? "btn-primary" : "btn-outline-secondary")"
                    @onclick="() => ThemeSvc.Theme = theme">
                @theme
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold" for="accent">Accent Color</label>
    <input id="accent" type="color" class="form-control form-control-color"
           value="@ThemeSvc.AccentColor"
           @onchange="OnAccentChanged" />
</div>

<p class="text-muted">
    Changes apply instantly to all components, including the header indicator.
</p>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChanged += HandleChanged;
    }

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeSvc.AccentColor = e.Value?.ToString() ?? "#1b6ec2";
    }

    private void HandleChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        ThemeSvc.OnChanged -= HandleChanged;
    }
}

