/* Theme variables */
:root,
[data-theme="light"] {
    --bg-color: #ffffff;
    --text-color: #212529;
    --accent-color: #1b6ec2;
    --surface-color: #f8f9fa;
}

[data-theme="dark"] {
    --bg-color: #1a1a2e;
    --text-color: #e0e0e0;
    --surface-color: #16213e;
    color-scheme: dark;
}

[data-theme="system"] {
    --bg-color: #ffffff;
    --text-color: #212529;
    --surface-color: #f8f9fa;
}

@media (prefers-color-scheme: dark) {
    [data-theme="system"] {
        --bg-color: #1a1a2e;
        --text-color: #e0e0e0;
        --surface-color: #16213e;
        color-scheme: dark;
    }
}

html, body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
    background-color: var(--bg-color);
    color: var(--text-color);
    transition: background-color 0.2s, color 0.2s;
}

